// Rate limiting per user
const levelCompletionLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 10,
  keyGenerator: (req) => req.userId || req.ip,
  message: { error: 'Too many requests. Please slow down.' }
});

const rewardClaimLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 20,
  keyGenerator: (req) => req.userId || req.ip,
  message: { error: 'Too many reward claims.' }
});

// Level configuration - server-side source of truth
