// ---- Anti-Bot / Anti-Cheat Utilities ----

function generateServerNonce() {
  return crypto.randomBytes(32).toString('hex');
}

function computePayloadHmac(payload, nonce) {
  const dataString = JSON.stringify(payload) + nonce;
  return crypto.createHmac('sha256', HMAC_SECRET).update(dataString).digest('hex');
}

function verifyPayloadHmac(payload, nonce, clientHmac) {
  const expected = computePayloadHmac(payload, nonce);
  return crypto.timingSafeEqual(Buffer.from(expected, 'hex'), Buffer.from(clientHmac, 'hex'));
}

// Behavioral analysis for bot detection
function analyzeBehavior(userId, levelId, completionData) {
  const anomalies = [];
  const profile = playerBehaviorProfiles.get(userId) || {
    completions: [],
    averageTimePerLevel: {},
    averageScorePerLevel: {},
    completionTimestamps: [],
    suspicionScore: 0,
    flagged: false,
  };

  const now = Date.now();

  // 1. Check for impossibly consistent timing (bots often have very consistent intervals)
  if (profile.completionTimestamps.length >= 3) {
    const recentTimestamps = profile.completionTimestamps.slice(-5);
    const intervals = [];
    for (let i = 1; i < recentTimestamps.length; i++) {
      intervals.push(recentTimestamps[i] - recentTimestamps[i - 1]);
    }
    if (intervals.length >= 2) {
      const avgInterval = intervals.reduce((a, b) => a + b, 0) / intervals.length;
      const variance = intervals.reduce((sum, val) => sum + Math.pow(val - avgInterval, 2), 0) / intervals.length;
      const coeffOfVariation = Math.sqrt(variance) / avgInterval;
      // Humans have natural variance; bots are suspiciously consistent
      if (coeffOfVariation < 0.05 && intervals.length >= 3) {
        anomalies.push({ type: 'consistent_timing', severity: 3, detail: `CV: ${coeffOfVariation.toFixed(4)}` });
      }
    }
  }

  // 2. Check move timing distribution (if provided)
  if (completionData.moveTimings && Array.isArray(completionData.moveTimings)) {
    const timings = completionData.moveTimings;
    if (timings.length > 5) {
      const avgTiming = timings.reduce((a, b) => a + b, 0) / timings.length;
      const variance = timings.reduce((sum, val) => sum + Math.pow(val - avgTiming, 2), 0) / timings.length;
      const cv = Math.sqrt(variance) / avgTiming;

      // Bots tend to have very uniform move timings
      if (cv < 0.08) {
        anomalies.push({ type: 'uniform_move_timing', severity: 4, detail: `Move timing CV: ${cv.toFixed(4)}` });
      }

      // Check for inhuman reaction times (< 50ms between moves)
      const tooFastMoves = timings.filter(t => t < 50).length;
      if (tooFastMoves / timings.length > 0.3) {
        anomalies.push({ type: 'inhuman_speed', severity: 5, detail: `${tooFastMoves}/${timings.length} moves < 50ms` });
      }
    }
  }

  // 3. Check for sequential perfect scores (statistically improbable)
  const recentCompletions = profile.completions.slice(-10);
  const perfectCount = recentCompletions.filter(c => {
    const config = LEVEL_CONFIG[c.levelId];
    return config && c.score >= config.maxScore * 0.98;
  }).length;
  if (recentCompletions.length >= 5 && perfectCount / recentCompletions.length > 0.9) {
    anomalies.push({ type: 'suspicious_perfection', severity: 3, detail: `${perfectCount}/${recentCompletions.length} near-perfect` });
  }

  // 4. Check for rapid level progression
  const recentTimestamps = profile.completionTimestamps.slice(-5);
  if (recentTimestamps.length >= 5) {
    const timeSpan = now - recentTimestamps[0];
    if (timeSpan < 60000) { // 5 levels in under 1 minute
      anomalies.push({ type: 'rapid_progression', severity: 4, detail: `5 levels in ${(timeSpan / 1000).toFixed(1)}s` });
    }
  }

  // 5. Check touch/input pattern entropy (if provided)
  if (completionData.inputPositions && Array.isArray(completionData.inputPositions)) {
    const positions = completionData.inputPositions;
    if (positions.length > 10) {
      // Check for grid-aligned inputs (bots often click exact coordinates)
      const xPositions = positions.map(p => p.x);
      const yPositions = positions.map(p => p.y);
      const uniqueX = new Set(xPositions.map(x => Math.round(x))).size;
      const uniqueY = new Set(yPositions.map(y => Math.round(y))).size;
      const positionEntropy = (uniqueX * uniqueY) / positions.length;
      if (positionEntropy < 0.1) {
        anomalies.push({ type: 'low_input_entropy', severity: 3, detail: `Position entropy: ${positionEntropy.toFixed(4)}` });
      }
    }
  }

  // 6. Verify time consistency: reported play time vs wall clock time
  if (completionData.sessionStartTimestamp) {
    const wallClockTime = (now - completionData.sessionStartTimestamp) / 1000;
    const reportedTime = completionData.timeSeconds;
    const timeDrift = Math.abs(wallClockTime - reportedTime);
    // Allow some tolerance for network latency and pausing
    if (timeDrift > reportedTime * 0.5 + 10) {
      anomalies.push({ type: 'time_manipulation', severity: 5, detail: `Wall: ${wallClockTime.toFixed(1)}s, Reported: ${reportedTime}s` });
    }
  }

  // Calculate suspicion score
  const severitySum = anomalies.reduce((sum, a) => sum + a.severity, 0);
  profile.suspicionScore = Math.min(100, profile.suspicionScore * 0.8 + severitySum * 5);

  if (profile.suspicionScore > 50) {
    profile.flagged = true;
  }

  // Update profile
  profile.completions.push({ levelId, score: completionData.score, time: completionData.timeSeconds, timestamp: now });
  if (profile.completions.length > 100) profile.completions = profile.completions.slice(-100);
  profile.completionTimestamps.push(now);
  if (profile.completionTimestamps.length > 50) profile.completionTimestamps = profile.completionTimestamps.slice(-50);

  playerBehaviorProfiles.set(userId, profile);

  return {
    anomalies,
    suspicionScore: profile.suspicionScore,
    flagged: profile.flagged,
    blocked: profile.suspicionScore > 80,
  };
}

// Replay validation: ensure the sequence of moves can produce the claimed score
function validateReplay(levelId, moves, claimedScore) {
  if (!moves || !Array.isArray(moves) || moves.length === 0) {
    return { valid: false, reason: 'No move data provided' };
  }

  const config = LEVEL_CONFIG[levelId];
  if (!config) {
    return { valid: false, reason: 'Invalid level' };
  }

  if (moves.length < config.minMoves) {
    return { valid: false, reason: `Too few moves: ${moves.length} < ${config.minMoves}` };
  }

  if (moves.length > config.maxMoves) {
    return { valid: false, reason: `Too many moves: ${moves.length} > ${config.maxMoves}` };
  }

  // Validate move structure
  for (let i = 0; i < moves.length; i++) {
    const move = moves[i];
    if (!move || typeof move.type !== 'string' || typeof move.timestamp !== 'number') {
      return { valid: false, reason: `Invalid move at index ${i}` };
    }
    // Ensure timestamps are monotonically increasing
    if (i > 0 && move.timestamp < moves[i - 1].timestamp) {
      return { valid: false, reason: `Non-monotonic timestamp at move ${i}` };
    }
  }

  // Server-side score simulation (simplified - in production this would be a full game logic replay)
  let simulatedScore = 0;
  const validMoveTypes = ['swap', 'match', 'powerup', 'cascade', 'combo'];
  const moveScores = { swap: 0, match: 10, powerup: 50, cascade: 30, combo: 100 };

  for (const move of moves) {
    if (!validMoveTypes.includes(move.type)) {
      return { valid: false, reason: `Unknown move type: ${move.type}` };
    }
    simulatedScore += moveScores[move.type] || 0;
    if (move.multiplier && typeof move.multiplier === 'number') {
      simulatedScore += moveScores[move.type] * (Math.min(move.multiplier, 5) - 1);
    }
  }

  // Allow some tolerance for floating point and bonus calculations
  const tolerance = 0.15;
  if (claimedScore > simulatedScore * (1 + tolerance)) {
    return {
      valid: false,
      reason: `Score mismatch: claimed ${claimedScore}, simulated max ${Math.floor(simulatedScore * (1 + tolerance))}`,
    };
  }

  return { valid: true, simulatedScore };
}

// Detect replay attacks by checking for duplicate submissions
function checkReplayAttack(userId, levelId, completionData) {
  const key = `${userId}:${levelId}`;
  const history = replayLog.get(key) || [];

  // Create a fingerprint of the completion
  const fingerprint = crypto.createHash('sha256')
    .update(JSON.stringify({
      score: completionData.score,
      moves: completionData.moves?.length,
      time: completionData.timeSeconds,
    }))
    .digest('hex');

  // Check for exact duplicate submissions
  const duplicate = history.find(h => h.fingerprint === fingerprint && (Date.now() - h.timestamp) < 3600000);
  if (duplicate) {
    return { isDuplicate: true, reason: 'Duplicate completion detected' };
  }

  history.push({ fingerprint, timestamp: Date.now() });
  if (history.length > 20) history.splice(0, history.length - 20);
  replayLog.set(key, history);

  return { isDuplicate: false };
}

// ---- Middleware ----

function authenticateToken(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const decoded = jwt.verify(token, JWT_SECRET);
    req.userId = decoded.userId;
    req.deviceId = decoded.deviceId;
    next();
  } catch (err) {
    return res.status(403).json({ error: 'Invalid or expired token' });
  }
}

function validateIntegrity(req, res, next) {
  const { nonce, hmac, payload } = req.body;

  if (!nonce || !hmac || !payload) {
    return res.status(400).json({ error: 'Missing integrity fields' });
  }

  // Verify nonce was issued by server and hasn't been used
  const nonceData = sessionNonces.get(nonce);
  if (!nonceData) {
    return res.status(400).json({ error: 'Invalid or expired nonce' });
  }

  if (nonceData.used) {
    return res.status(400).json({ error: 'Nonce already consumed' });
  }

  // Check nonce expiry (5 minutes)
  if (Date.now() - nonceData.createdAt > 5 * 60 * 1000) {
    sessionNonces.delete(nonce);
    return res.status(400).json({ error: 'Nonce expired' });
  }

  // Verify nonce belongs to this user
  if (nonceData.userId !== req.userId) {
    return res.status(403).json({ error: 'Nonce user mismatch' });
  }

  // Verify HMAC
  try {
    if (!verifyPayloadHmac(payload, nonce, hmac)) {
      return res.status(400).json({ error: 'Integrity check failed' });
    }
  } catch (err) {
    return res.status(400).json({ error: 'Integrity verification error' });
  }

  // Mark nonce as used
  nonceData.used = true;
  sessionNonces.set(nonce, nonceData);

  // Schedule cleanup
  setTimeout(() => sessionNonces.delete(nonce), 60000);

  req.validatedPayload = payload;
  next();
}

// ---- Auth Endpoints ----

app.post('/api/auth/register', (req, res) => {
  const { username, deviceId, deviceFingerprint } = req.body;

  if (!username || !deviceId) {
    return res.status(400).json({ error: 'Username and deviceId required' });
  }

  const userId = crypto.randomUUID();
  users.set(userId, {
    username,
    deviceId,
    deviceFingerprint,
    coins: 0,
    stars: 0,
    createdAt: Date.now(),
    lastLogin: Date.now(),
  });

  completedLevels.set(userId, new Map());
  pendingRewards.set(userId, []);

  const token = jwt.sign({ userId, deviceId }, JWT_SECRET, { expiresIn: '24h' });

  res.json({
    userId,
    token,
    message: 'Registration successful',
  });
});

app.post('/api/auth/login', (req, res) => {
  const { userId, deviceId } = req.body;

  const user = users.get(userId);
  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }

  if (user.deviceId !== deviceId) {
    return res.status(403).json({ error: 'Device mismatch' });
  }

  user.lastLogin = Date.now();
  const token = jwt.sign({ userId, deviceId }, JWT_SECRET, { expiresIn: '24h' });

  res.json({ token, user: { coins: user.coins, stars: user.stars } });
});

// ---- Nonce Endpoint ----

app.post('/api/session/nonce', authenticateToken, (req, res) => {
  const nonce = generateServerNonce();
  sessionNonces.set(nonce, {
    userId: req.userId,
    createdAt: Date.now(),
    used: false,
  });

  // Clean up old nonces periodically
  if (sessionNonces.size > 10000) {
    const now = Date.now();
    for (const [key, val] of sessionNonces) {
      if (now - val.createdAt > 10 * 60 * 1000) {
        sessionNonces.delete(key);
      }
    }
  }

  res.json({ nonce });
});

// ---- Level Start (server records when a level attempt begins) ----

app.post('/api/levels/:levelId/start', authenticateToken, (req, res) => {
  const levelId = parseInt(req.params.levelId);
  const config = LEVEL_CONFIG[levelId];

  if (!config) {
    return res.status(404).json({ error: 'Level not found' });
  }

  const user = users.get(req.userId);
  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }

  // Check if player has unlocked this level (must complete previous)
  if (levelId > 1) {
    const userLevels = completedLevels.get(req.userId);
    if (!userLevels || !userLevels.has(levelId - 1)) {
      return res.status(403).json({ error: 'Previous level not completed' });
    }
  }

  // Record level start time server-side
  const sessionToken = crypto.randomBytes(16).toString('hex');
  const startData = {
    userId: req.userId,
    levelId,
    startedAt: Date.now(),
    sessionToken,
  };

  // Store with a key combining user and level
  const startKey = `start:${req.userId}:${levelId}`;
  sessionNonces.set(startKey, startData);

  res.json({
    sessionToken,
    levelConfig: {
      maxMoves: config.maxMoves,
      maxTime: config.maxTime,
    },
  });
});

// ---- Level Completion ----

app.post('/api/levels/:levelId/complete',
  authenticateToken,
  levelCompletionLimiter,
  validateIntegrity,
  (req, res) => {
    const levelId = parseInt(req.params.levelId);
    const config = LEVEL_CONFIG[levelId];

    if (!config) {
      return res.status(404).json({ error: 'Level not found' });
    }

    const user = users.get(req.userId);
    if (!user) {
      return res.status(404).json({ error: 'User not found' });
    }

    const payload = req.validatedPayload;
    const {
      score,
      timeSeconds,
      moves,
      moveTimings,
      inputPositions,
      sessionToken,
      sessionStartTimestamp,
      clientVersion,
    } = payload;

    // ---- Basic Validation ----
    if (typeof score !== 'number' || typeof timeSeconds !== 'number') {
      return res.status(400).json({ error: 'Invalid completion data' });
    }

    if (score < 0 || score > config.maxScore) {
      return res.status(400).json({ error: 'Score out of valid range' });
    }

    if (timeSeconds < config.minTime || timeSeconds > config.maxTime) {
      return res.status(400).json({ error: 'Completion time out of valid range' });
    }

    // ---- Verify Level Start Session ----
    const startKey = `start:${req.userId}:${levelId}`;
    const startData = sessionNonces.get(startKey);

    if (!startData || startData.sessionToken !== sessionToken) {
      return res.status(400).json({ error: 'Invalid session. Did you start this level?' });
    }

    // Verify server-side elapsed time matches reported time
    const serverElapsed = (Date.now() - startData.startedAt) / 1000;
    if (serverElapsed < config.minTime) {
      return res.status(400).json({ error: 'Level completed impossibly fast (server time check)' });
    }

    // Allow reasonable tolerance for network latency
    if (Math.abs(serverElapsed - timeSeconds) > timeSeconds * 0.3 + 15) {
      return res.status(400).json({
        error: 'Time discrepancy between client and server',
        detail: `Server: ${serverElapsed.toFixed(1)}s, Client: ${timeSeconds}s`,
      });
    }

    // Clean up start session
    sessionNonces.delete(startKey);

    // ---- Replay Attack Detection ----
    const replayCheck = checkReplayAttack(req.userId, levelId, payload);
    if (replayCheck.isDuplicate) {
      return res.status(409).json({ error: replayCheck.reason });
    }

    // ---- Move Replay Validation ----
    const replayValidation = validateReplay(levelId, moves, score);
    if (!replayValidation.valid) {
      return res.status(400).json({
        error: 'Move validation failed',
        detail: replayValidation.reason,
      });
    }

    // ---- Behavioral Analysis ----
    const behaviorAnalysis = analyzeBehavior(req.userId, levelId, {
      score,
      timeSeconds,
      moves,
      moveTimings,
      inputPositions,
      sessionStartTimestamp,
    });

    if (behaviorAnalysis.blocked) {
      console.log(`[SECURITY] User ${req.userId} BLOCKED. Suspicion: ${behaviorAnalysis.suspicionScore}`, behaviorAnalysis.anomalies);
      return res.status(403).json({
        error: 'Suspicious activity detected. Your account has been flagged for review.',
      });
    }

    if (behaviorAnalysis.flagged) {
      console.log(`[SECURITY] User ${req.userId} FLAGGED. Suspicion: ${behaviorAnalysis.suspicionScore}`, behaviorAnalysis.anomalies);
      // Still allow but reduce rewards and log for manual review
    }

    // ---- Calculate Server-Authoritative Score ----
    // Use the minimum of client-reported score and server-simulated score
    const authorizedScore = Math.min(score, replayValidation.simulatedScore || score);

    // ---- Determine Reward Tier ----
    const scorePercent = (authorizedScore / config.maxScore) * 100;
    const timePercent = (timeSeconds / config.maxTime) * 100;

    let tier = 'complete';
    for (const [tierName, tierConfig] of Object.entries(REWARD_TIERS)) {
      if (scorePercent >= tierConfig.minScorePercent && timePercent <= tierConfig.maxTimePercent) {
        tier = tierName;
        break;
      }
    }

    const tierConfig = REWARD_TIERS[tier];
    let rewardMultiplier = tierConfig.multiplier;

    // Reduce rewards for flagged accounts (shadow penalty)
    if (behaviorAnalysis.flagged) {
      rewardMultiplier *= 0.5;
    }

    const rewards = {
      coins: Math.floor(config.rewards.coins * rewardMultiplier),
      stars: Math.floor(config.rewards.stars * rewardMultiplier),
    };

    // ---- Store Completion ----
    const userLevels = completedLevels.get(req.userId) || new Map();
    const existingCompletion = userLevels.get(levelId);

    // Only improve on existing completion, don't allow downgrade
    const completion = {
      levelId,
      score: authorizedScore,
      timeSeconds,
      tier,
      completedAt: Date.now(),
      moveCount: moves ? moves.length : 0,
      rewards,
      attempt: existingCompletion ? existingCompletion.attempt + 1 : 1,
    };

    // If already completed, only award difference in rewards
    let actualRewards = { ...rewards };
    if (existingCompletion) {
      actualRewards.coins = Math.max(0, rewards.coins - existingCompletion.rewards.coins);
      actualRewards.stars = Math.max(0, rewards.stars - existingCompletion.rewards.stars);

      if (authorizedScore > existingCompletion.score) {
        userLevels.set(levelId, completion);
      }
    } else {
      userLevels.set(levelId, completion);
    }

    completedLevels.set(req.userId, userLevels);

    // Queue rewards for claiming
    if (actualRewards.coins > 0 || actualRewards.stars > 0) {
      const rewardId = crypto.randomUUID();
      const userRewards = pendingRewards.get(req.userId) || [];
      userRewards.push({
        rewardId,
        levelId,
        rewards: actualRewards,
        tier,
        createdAt: Date.now(),
        claimed: false,
        expiresAt: Date.now() + 24 * 60 * 60 * 1000, // 24 hour expiry
      });
      pendingRewards.set(req.userId, userRewards);

      res.json({
        success: true,
        levelId,
        authorizedScore,
        tier,
        rewards: actualRewards,
        rewardId,
        isNewBest: !existingCompletion || authorizedScore > existingCompletion.score,
        message: existingCompletion ? 'Level re-completed' : 'Level completed!',
      });
    } else {
      res.json({
        success: true,
        levelId,
        authorizedScore,
        tier,
        rewards: actualRewards,
        isNewBest: false,
        message: 'Level completed but no additional rewards (already earned maximum)',
      });
    }
  }
);

// ---- Claim Rewards ----

app.post('/api/rewards/claim',
  authenticateToken,
  rewardClaimLimiter,
  validateIntegrity,
  (req, res) => {
    const { rewardId } = req.validatedPayload;

    if (!rewardId) {
      return res.status(400).json({ error: 'rewardId required' });
    }

    const user = users.get(req.userId);
    if (!user) {
      return res.status(404).json({ error: 'User not found' });
    }

    const userRewards = pendingRewards.get(req.userId) || [];
    const rewardIndex = userRewards.findIndex(r => r.rewardId === rewardId);

    if (rewardIndex === -1) {
      return res.status(404).json({ error: 'Reward not found' });
    }

    const reward = userRewards[rewardIndex];

    if (reward.claimed) {
      return res.status(409).json({ error: 'Reward already claimed' });
    }

    if (Date.now() > reward.expiresAt) {
      userRewards.splice(rewardIndex, 1);
      pendingRewards.set(req.userId, userRewards);
      return res.status(410).json({ error: 'Reward expired' });
    }

    // Apply rewards
    user.coins += reward.rewards.coins;
    user.stars += reward.rewards.stars;
    reward.claimed = true;
    reward.claimedAt = Date.now();

    users.set(req.userId, user);
    pendingRewards.set(req.userId, userRewards);

    res.json({
      success: true,
      claimed: reward.rewards,
      totals: {
        coins: user.coins,
        stars: user.stars,
      },
    });
  }
);

// ---- Claim All Pending Rewards ----

app.post('/api/rewards/claim-all',
  authenticateToken,
  rewardClaimLimiter,
  validateIntegrity,
  (req, res) => {
    const user = users.get(req.userId);
    if (!user) {
      return res.status(404).json({ error: 'User not found' });
    }

    const userRewards = pendingRewards.get(req.userId) || [];
    const now = Date.now();

    let totalCoins = 0;
    let totalStars = 0;
    let claimedCount = 0;

    for (const reward of userRewards) {
      if (!reward.claimed && now <= reward.expiresAt) {
        totalCoins += reward.rewards.coins;
        totalStars += reward.rewards.stars;
        reward.claimed = true;
        reward.claimedAt = now;
        claimedCount++;
      }
    }

    user.coins += totalCoins;
    user.stars += totalStars;

    users.set(req.userId, user);
    pendingRewards.set(req.userId, userRewards);

    res.json({
      success: true,
      claimedCount,
      claimed: { coins: totalCoins, stars: totalStars },
      totals: { coins: user.coins, stars: user.stars },
    });
  }
);

// ---- Get Pending Rewards ----

app.get('/api/rewards/pending', authenticateToken, (req, res) => {
  const userRewards = (pendingRewards.get(req.userId) || [])
    .filter(r => !r.claimed && Date.now() <= r.expiresAt)
    .map(r => ({
      rewardId: r.rewardId,
      levelId: r.levelId,
      rewards: r.rewards,
      tier: r.tier,
      expiresAt: r.expiresAt,
    }));

  res.json({ rewards: userRewards });
});

// ---- Player Progress ----

app.get('/api/player/progress', authenticateToken, (req, res) => {
  const user = users.get(req.userId);
  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }

  const userLevels = completedLevels.get(req.userId) || new Map();
  const levels = {};
  for (const [levelId, data] of userLevels) {
    levels[levelId] = {
      score: data.score,
      tier: data.tier,
      timeSeconds: data.timeSeconds,
      completedAt: data.completedAt,
      attempts: data.attempt,
    };
  }

  res.json({
    userId: req.userId,
    username: user.username,
    coins: user.coins,
    stars: user.stars,
    completedLevels: levels,
    nextLevel: Math.max(...[0, ...Object.keys(levels).map(Number)]) + 1,
  });
});

// ---- Admin: View Flagged Players ----

app.get('/api/admin/flagged', (req, res) => {
  const adminKey = req.headers['x-admin-key'];
  if (adminKey !== process.env.ADMIN_KEY) {
    return res.status(403).json({ error: 'Unauthorized' });
  }

  const flagged = [];
  for (const [userId, profile] of playerBehaviorProfiles) {
    if (profile.flagged) {
      const user = users.get(userId);
      flagged.push({
        userId,
        username: user?.username,
        suspicionScore: profile.suspicionScore,
        recentCompletions: profile.completions.slice(-5),
        totalCompletions: profile.completions.length,
      });
    }
  }

  res.json({ flaggedPlayers: flagged, count: flagged.length });
});

// ---- Health Check ----

app.get('/api/health', (req, res) => {
  res.json({
    status: 'ok',
    timestamp: Date.now(),
    activeSessions: sessionNonces.size,
    registeredUsers: users.size,
  });
});

// ---- Error Handler ----

app.use((err, req, res, next) => {
  console.error('[ERROR]', err.message);
  res.status(500).json({ error: 'Internal server error' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Game API server running on port ${PORT}`);
  console.log('Anti-cheat systems: HMAC integrity, behavioral analysis, replay validation, nonce protection');
});

module.exports = app;